static int g_passed = 0;
static int g_failed = 0;

#define ASSERT_TRUE(expr, msg)                                         \
    do {                                                               \
        if (expr) { printf("  [PASS] %s\n", msg); g_passed++; }       \
        else      { printf("  [FAIL] %s\n", msg); g_failed++; }       \
    } while (0)

#define ASSERT_NEAR(actual, expected, tol, msg)                        \
    do {                                                               \
        float _a = (actual), _e = (expected);                          \
        if (fabsf(_a - _e) <= (tol)) {                                \
            printf("  [PASS] %s\n", msg);                              \
            g_passed++;                                                \
        } else {                                                       \
            printf("  [FAIL] %s  (expected %.6f, got %.6f)\n",         \
                   msg, (double)_e, (double)_a);                       \
            g_failed++;                                                \
        }                                                              \
    } while (0)

#define EPS 1e-4f

/* helper: upload host array, run on GPU, download result */
static void upload(float* d_dst, const float* h_src, int n) {
    cuda_copy_to_device(d_dst, h_src, n);
}
static void download(float* h_dst, const float* d_src, int n) {
    cuda_copy_to_host(h_dst, d_src, n);
    cudaDeviceSynchronize();
}

