static void test_relu_backward(void) {
    printf("\n--- test_relu_backward ---\n");
    //  z (pre-activation):  positive -> gradient passes, negative -> gradient dies
    float z[]  = {2.0f, -1.0f, 0.5f, -3.0f};
    float dA[] = {1.0f,  1.0f, 1.0f,  1.0f};
    float out[4];
    int n = 4;

    float *d_z = cuda_malloc_float(n), *d_dA = cuda_malloc_float(n), *d_o = cuda_malloc_float(n);
    upload(d_z, z, n); upload(d_dA, dA, n);

    cuda_relu_backward(d_z, d_dA, d_o, n);
    download(out, d_o, n);

    ASSERT_NEAR(out[0], 1.0f, EPS, "relu_back(z=2, dA=1) == 1  (active)");
    ASSERT_NEAR(out[1], 0.0f, EPS, "relu_back(z=-1, dA=1) == 0 (dead)");
    ASSERT_NEAR(out[2], 1.0f, EPS, "relu_back(z=0.5, dA=1) == 1 (active)");
    ASSERT_NEAR(out[3], 0.0f, EPS, "relu_back(z=-3, dA=1) == 0 (dead)");

    cuda_free(d_z); cuda_free(d_dA); cuda_free(d_o);
}

