    float *d_A = cuda_malloc_float(4), *d_I = cuda_malloc_float(4), *d_C = cuda_malloc_float(4);
    upload(d_A, A, 4); upload(d_I, I, 4);

    cuda_matmul(d_A, d_I, d_C, 2, 2, 2);
