    ASSERT_NEAR(C[2], 3.0f, EPS, "A*I [1,0] == 3");
    ASSERT_NEAR(C[3], 4.0f, EPS, "A*I [1,1] == 4");

    cuda_free(d_A); cuda_free(d_I); cuda_free(d_C);
}

