static void test_matmul_transA(void) {
    printf("\n--- test_matmul_transA ---\n");
    // A stored as (K x M) = (2x2): [1 3]   -> A^T = [1 2]
    //                                [2 4]            [3 4]
    // B = (K x N) = (2x2): [5 6]
    //                       [7 8]
    // C = A^T * B (M=2,K=2,N=2) = [1*5+2*7  1*6+2*8] = [19 22]
    //                               [3*5+4*7  3*6+4*8]   [43 50]
    float A[] = {1, 3, 2, 4};
    float B[] = {5, 6, 7, 8};
    float C[4];

    float *d_A = cuda_malloc_float(4), *d_B = cuda_malloc_float(4), *d_C = cuda_malloc_float(4);
    upload(d_A, A, 4); upload(d_B, B, 4);

    cuda_matmul_transA(d_A, d_B, d_C, 2, 2, 2);
    download(C, d_C, 4);

    ASSERT_NEAR(C[0], 19.0f, EPS, "A^T*B [0,0] == 19");
    ASSERT_NEAR(C[1], 22.0f, EPS, "A^T*B [0,1] == 22");
    ASSERT_NEAR(C[2], 43.0f, EPS, "A^T*B [1,0] == 43");
    ASSERT_NEAR(C[3], 50.0f, EPS, "A^T*B [1,1] == 50");

    cuda_free(d_A); cuda_free(d_B); cuda_free(d_C);
}

