/* ================================================================== */
/*  BATCHNORM TESTS                                                   */
/* ================================================================== */
/* Layout: data is (features x batch_size), feature-major.            */

static void test_batchnorm_forward_zero_mean_unit_var(void) {
    printf("\n--- test_batchnorm_forward_zero_mean_unit_var ---\n");
    // 1 feature, batch of 3: values [1, 4, 7]
    // mean = 4, var = 6, std = sqrt(6 + eps)
    // gamma=1, beta=0 -> output is just x_hat (normalized)
    int features = 1, batch = 3;
    float in[]    = {1.0f, 4.0f, 7.0f};
    float gamma[] = {1.0f};
    float beta[]  = {0.0f};
    float out[3], mean[1], var[1];
    float eps = 1e-5f;

    float *d_in = cuda_malloc_float(3), *d_out = cuda_malloc_float(3);
    float *d_g  = cuda_malloc_float(1), *d_b   = cuda_malloc_float(1);
    float *d_m  = cuda_malloc_float(1), *d_v   = cuda_malloc_float(1);
    upload(d_in, in, 3); upload(d_g, gamma, 1); upload(d_b, beta, 1);

    cuda_batchnorm_forward(d_in, d_out, d_g, d_b, d_m, d_v, features, batch, eps);
    download(out, d_out, 3);
    download(mean, d_m, 1);
    download(var, d_v, 1);

    ASSERT_NEAR(mean[0], 4.0f, EPS, "mean == 4.0");
    ASSERT_NEAR(var[0],  6.0f, EPS, "var == 6.0");

    float inv_std = 1.0f / sqrtf(6.0f + eps);
    ASSERT_NEAR(out[0], (1.0f - 4.0f) * inv_std, EPS, "x_hat[0] normalized");
    ASSERT_NEAR(out[1], (4.0f - 4.0f) * inv_std, EPS, "x_hat[1] ~= 0 (at mean)");
    ASSERT_NEAR(out[2], (7.0f - 4.0f) * inv_std, EPS, "x_hat[2] normalized");

    cuda_free(d_in); cuda_free(d_out); cuda_free(d_g);
    cuda_free(d_b);  cuda_free(d_m);   cuda_free(d_v);
}

static void test_batchnorm_forward_with_scale_shift(void) {
    printf("\n--- test_batchnorm_forward_with_scale_shift ---\n");
    // 1 feature, batch of 2: [2, 4], mean=3, var=1
    // gamma=2, beta=5 -> y = 2*x_hat + 5
    int features = 1, batch = 2;
    float in[]    = {2.0f, 4.0f};
    float gamma[] = {2.0f};
    float beta[]  = {5.0f};
    float out[2], mean[1], var[1];
    float eps = 1e-5f;

    float *d_in = cuda_malloc_float(2), *d_out = cuda_malloc_float(2);
    float *d_g  = cuda_malloc_float(1), *d_b   = cuda_malloc_float(1);
    float *d_m  = cuda_malloc_float(1), *d_v   = cuda_malloc_float(1);
    upload(d_in, in, 2); upload(d_g, gamma, 1); upload(d_b, beta, 1);

    cuda_batchnorm_forward(d_in, d_out, d_g, d_b, d_m, d_v, features, batch, eps);
    download(out, d_out, 2);
    download(mean, d_m, 1);
    download(var, d_v, 1);

    float inv_std = 1.0f / sqrtf(1.0f + eps);
    float expected_0 = 2.0f * (2.0f - 3.0f) * inv_std + 5.0f;
    float expected_1 = 2.0f * (4.0f - 3.0f) * inv_std + 5.0f;

    ASSERT_NEAR(mean[0], 3.0f, EPS, "mean == 3.0");
    ASSERT_NEAR(var[0],  1.0f, EPS, "var == 1.0");
    ASSERT_NEAR(out[0], expected_0, EPS, "y[0] = gamma*x_hat + beta");
    ASSERT_NEAR(out[1], expected_1, EPS, "y[1] = gamma*x_hat + beta");

    cuda_free(d_in); cuda_free(d_out); cuda_free(d_g);
    cuda_free(d_b);  cuda_free(d_m);   cuda_free(d_v);
}

static void test_batchnorm_backward_dgamma_dbeta(void) {
    printf("\n--- test_batchnorm_backward_dgamma_dbeta ---\n");
    // 1 feature, batch of 2: in=[2, 4], mean=3, var=1
    // dout = [1, 1]
    // dbeta = sum(dout) = 2
    // dgamma = sum(dout * x_hat)
    int features = 1, batch = 2;
    float in[]    = {2.0f, 4.0f};
    float dout_h[]= {1.0f, 1.0f};
    float gamma[] = {1.0f};
    float mean_h[]= {3.0f};
    float var_h[] = {1.0f};
    float eps = 1e-5f;

    float din[2], dgamma[1], dbeta[1];

    float *d_dout = cuda_malloc_float(2), *d_in = cuda_malloc_float(2);
    float *d_m = cuda_malloc_float(1), *d_v = cuda_malloc_float(1), *d_g = cuda_malloc_float(1);
    float *d_din = cuda_malloc_float(2), *d_dg = cuda_malloc_float(1), *d_db = cuda_malloc_float(1);

    upload(d_dout, dout_h, 2); upload(d_in, in, 2);
    upload(d_m, mean_h, 1);    upload(d_v, var_h, 1);
    upload(d_g, gamma, 1);

    cuda_batchnorm_backward(d_dout, d_in, d_m, d_v, d_g, d_din, d_dg, d_db, features, batch, eps);
    download(dgamma, d_dg, 1);
    download(dbeta, d_db, 1);

    float inv_std = 1.0f / sqrtf(1.0f + eps);
    float x_hat_0 = (2.0f - 3.0f) * inv_std;
    float x_hat_1 = (4.0f - 3.0f) * inv_std;
    float expected_dgamma = x_hat_0 + x_hat_1;

    ASSERT_NEAR(dbeta[0],  2.0f,            EPS, "dbeta = sum(dout) == 2");
    ASSERT_NEAR(dgamma[0], expected_dgamma, EPS, "dgamma = sum(dout * x_hat)");

    cuda_free(d_dout); cuda_free(d_in); cuda_free(d_m);
    cuda_free(d_v); cuda_free(d_g); cuda_free(d_din);
    cuda_free(d_dg); cuda_free(d_db);
}

/* ================================================================== */
/*  CONV2D (im2col / col2im) TESTS                                   */
/* ================================================================== */

static void test_im2col_1x1_kernel_is_identity(void) {
    printf("\n--- test_im2col_1x1_kernel_is_identity ---\n");
    // 1 channel, 2x2 image, 1x1 kernel, stride=1, pad=0
    // im2col with 1x1 kernel should just copy the input
    float in[] = {1.0f, 2.0f, 3.0f, 4.0f};
    int C_in = 1, H = 2, W = 2, kH = 1, kW = 1, stride = 1, pad = 0;
    int out_H = 2, out_W = 2;
    int col_size = C_in * kH * kW * out_H * out_W;  // 4
    float col[4];

    float *d_in = cuda_malloc_float(4), *d_col = cuda_malloc_float(col_size);
    upload(d_in, in, 4);

    cuda_im2col(d_in, C_in, H, W, kH, kW, stride, pad, d_col);
    download(col, d_col, col_size);

    ASSERT_NEAR(col[0], 1.0f, EPS, "im2col 1x1: [0] == 1");
    ASSERT_NEAR(col[1], 2.0f, EPS, "im2col 1x1: [1] == 2");
    ASSERT_NEAR(col[2], 3.0f, EPS, "im2col 1x1: [2] == 3");
    ASSERT_NEAR(col[3], 4.0f, EPS, "im2col 1x1: [3] == 4");

    cuda_free(d_in); cuda_free(d_col);
}

static void test_im2col_3x3_with_padding(void) {
    printf("\n--- test_im2col_3x3_with_padding ---\n");
    // 1 channel, 3x3 image, 3x3 kernel, stride=1, pad=1 -> out 3x3
    // just verify the center patch (oh=1,ow=1) which covers the full image
    float in[] = {1, 2, 3,
                  4, 5, 6,
                  7, 8, 9};
    int C_in = 1, H = 3, W = 3, kH = 3, kW = 3, stride = 1, pad = 1;
    int out_H = 3, out_W = 3;
    int col_size = C_in * kH * kW * out_H * out_W;  // 81
    float* col = (float*)malloc(col_size * sizeof(float));

    float *d_in = cuda_malloc_float(9), *d_col = cuda_malloc_float(col_size);
    upload(d_in, in, 9);

    cuda_im2col(d_in, C_in, H, W, kH, kW, stride, pad, d_col);
    download(col, d_col, col_size);

    // center output pixel (oh=1, ow=1) should see the full 3x3 image
    // col layout: for each (c, kh, kw) we have out_H*out_W values
    // pixel (oh=1,ow=1) index within each kernel position = 1*out_W + 1 = 4
    // position (c=0,kh=0,kw=0): index 0*9 + 4 = 4
    // position (c=0,kh=1,kw=1): index 4*9 + 4 = 40   -> center of kernel = center of image = 5
    ASSERT_NEAR(col[4*9 + 4], 5.0f, EPS, "center patch, center pixel == 5 (image center)");

    // top-left corner of center patch: (c=0,kh=0,kw=0) at (oh=1,ow=1)
    // maps to in[0*3+0] = 1
    ASSERT_NEAR(col[0*9 + 4], 1.0f, EPS, "center patch, top-left == 1");

    free(col);
    cuda_free(d_in); cuda_free(d_col);
}

static void test_col2im_reverses_im2col(void) {
    printf("\n--- test_col2im_reverses_im2col ---\n");
    // 1 channel, 2x2 image, 1x1 kernel, stride=1, pad=0
    // im2col then col2im should recover the original
    float in[] = {10.0f, 20.0f, 30.0f, 40.0f};
    int C_in = 1, H = 2, W = 2, kH = 1, kW = 1, stride = 1, pad = 0;
    int col_size = 4;
    float recovered[4];

    float *d_in = cuda_malloc_float(4), *d_col = cuda_malloc_float(col_size), *d_rec = cuda_malloc_float(4);
    upload(d_in, in, 4);

    cuda_im2col(d_in, C_in, H, W, kH, kW, stride, pad, d_col);

    cuda_memset_zero(d_rec, 4);
    cuda_col2im(d_col, C_in, H, W, kH, kW, stride, pad, d_rec);
    download(recovered, d_rec, 4);

    ASSERT_NEAR(recovered[0], 10.0f, EPS, "col2im recovers [0] == 10");
    ASSERT_NEAR(recovered[1], 20.0f, EPS, "col2im recovers [1] == 20");
    ASSERT_NEAR(recovered[2], 30.0f, EPS, "col2im recovers [2] == 30");
    ASSERT_NEAR(recovered[3], 40.0f, EPS, "col2im recovers [3] == 40");

    cuda_free(d_in); cuda_free(d_col); cuda_free(d_rec);
}

/* ================================================================== */

int main(void) {
    printf("========== CUDA KERNEL UNIT TESTS ==========\n");

    cuda_backend_init();

    /* elementwise */
    test_add();
    test_sub();
    test_mul();
    test_scale();

    /* activations forward */
    test_relu_forward();
    test_sigmoid_forward();
    test_tanh_forward();

    /* activations backward */
    test_relu_backward();
    test_sigmoid_backward();
    test_tanh_backward();
    test_sigmoid_backward_scales_by_dA();

    /* reduce */
    test_sum_rows();
    test_sum_cols();
    test_sum_rows_single_row();

    /* matmul */
    test_matmul_identity();
    test_matmul_2x3_times_3x2();
    test_matmul_transA();
    test_matmul_transB();

    /* batchnorm */
    test_batchnorm_forward_zero_mean_unit_var();
    test_batchnorm_forward_with_scale_shift();
    test_batchnorm_backward_dgamma_dbeta();

    /* conv2d */
    test_im2col_1x1_kernel_is_identity();
    test_im2col_3x3_with_padding();
    test_col2im_reverses_im2col();

    printf("\n============================================\n");
    printf("Results: %d passed, %d failed\n", g_passed, g_failed);
    printf("============================================\n");

    cuda_backend_cleanup();
    return g_failed > 0 ? 1 : 0;
}
